Here's a modern MSTest test class covering async success, failure, timeout, and cancellation:

```csharp
[TestClass]
public class DataFetcherTests
{
    private MockHttpMessageHandler _handler = null!;
    private DataFetcher _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _handler = new MockHttpMessageHandler();
        _sut = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        };

        var result = await _sut.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpError()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => _sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(3000)] // fails the test if it hangs longer than 3s
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("fast")
        };

        var result = await _sut.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOnCancellation()
    {
        // Simulate a slow server
        _handler.Delay = TimeSpan.FromSeconds(10);
        _handler.Response = new HttpResponseMessage(HttpStatusCode.OK);

        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => _sut.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal test double — avoids external mocking libraries
    private class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK);
        public TimeSpan Delay { get; set; } = TimeSpan.Zero;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (Delay > TimeSpan.Zero)
                await Task.Delay(Delay, cancellationToken);

            return Response;
        }
    }
}
```

**Key patterns used:**

- **`async Task` test methods** — MSTest natively awaits them; never use `async void`.
- **`[Timeout(ms)]`** — guards against tests that hang; MSTest cancels the test automatically.
- **`CancellationToken` propagation** — the `Delay` in the handler lets you prove the token is actually forwarded through `GetAsync`.
- **`Assert.ThrowsExceptionAsync<T>`** — the async counterpart for exception assertions (don't use the sync version with async lambdas).
- **Custom `HttpMessageHandler`** — avoids mocking `HttpClient` directly (which isn't designed for it) and avoids a Moq/NSubstitute dependency.
